                            "tier": "intro",
                            "code": "# === ENTRY-LEVEL EXAMPLE ===\n# TASK      - Basic usage of Typer & Click — Building CLI Applications — understand the core syntax and behavior.\n# APPROACH  - Simple example with minimal parameters; no edge cases.\n# STRENGTHS - Clear, readable; shows the fundamental pattern.\n# WEAKNESSES- Not production-ready; no error handling or complex scenarios.\nimport argparse\nfrom pathlib import Path\np = argparse.ArgumentParser(prog=\"proc\", description=\"Process a data file\")\np.add_argument(\"input\", type=Path, help=\"input file\")\np.add_argument(\"-o\", \"--output\", type=Path, default=Path(\"out.json\"))\np.add_argument(\"-f\", \"--format\", choices=[\"json\", \"csv\"], default=\"json\")\np.add_argument(\"-v\", \"--verbose\", action=\"store_true\")\nargs = p.parse_args()\nif args.verbose:\n    print(f\"reading {args.input} as {args.format} -> {args.output}\")"
